import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Select,
  LinListFilterDateRangeField,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  type LinListToolbarActionDef,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { AttendanceRecordDto, DepartmentDto } from '../../../services/ns/models';
import { chamCongPageLabels as labels } from '../../../constants/chamCongPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useHrAttendancePermissions } from '../../../hooks/useHrPermissions';
import { formatDateLocal, formatTime } from '../../../utils/format';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-cham-cong';
const PAGE_ID = 'ns-cham-cong';
const PAGE_SIZE = 50;

const ChamCongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const perms = useHrAttendancePermissions();
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
  const monthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().slice(0, 10);

  const [reloadKey, setReloadKey] = useState(0);
  const [fromDate, setFromDate] = useState(monthStart);
  const [toDate, setToDate] = useState(monthEnd);
  const [departmentId, setDepartmentId] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [depts, setDepts] = useState<DepartmentDto[]>([]);
  const [items, setItems] = useState<AttendanceRecordDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [syncing, setSyncing] = useState(false);
  const [syncConfirm, setSyncConfirm] = useState(false);

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
  }, []);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      hrService
        .getDepartments()
        .then(d => {
          if (!cancelled) setDepts(d);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService
        .getAttendance({
          fromDate,
          toDate,
          departmentId: departmentId || undefined,
          page: currentPage,
          pageSize: PAGE_SIZE,
        })
        .then(res => {
          if (!cancelled) {
            setItems(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [dispatch, fromDate, toDate, departmentId, currentPage, reloadKey]);

  const lateCount = items.filter(r => r.isLate).length;

  const handleSync = useCallback(async () => {
    setSyncing(true);
    try {
      await hrService.syncAttendance();
      dispatchAppToast(dispatch, { message: labels.syncSuccess, type: 'success' });
      setSyncConfirm(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.syncError),
        type: 'error',
      });
    } finally {
      setSyncing(false);
    }
  }, [dispatch, refresh]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const headerHint = useMemo(
    () => `Đi trễ: ${lateCount} · Tổng bản ghi: ${totalCount}`,
    [lateCount, totalCount],
  );

  const toolbarActions = useMemo((): LinListToolbarActionDef[] => {
    const left: LinListToolbarActionDef[] = [
      {
        id: 'refresh',
        placement: 'left',
        action: 'refresh',
        visible: true,
        disabled: syncing,
        onClick: refresh,
        testId: `${TEST_ID}-toolbar-refresh-btn`,
      },
    ];

    if (!perms.canWrite) return left;

    if (syncConfirm) {
      return [
        ...left,
        {
          id: 'sync-confirm',
          placement: 'right',
          label: labels.syncConfirm,
          variant: 'primary',
          visible: true,
          disabled: syncing,
          onClick: handleSync,
          testId: `${TEST_ID}-toolbar-sync-confirm-btn`,
        },
        {
          id: 'sync-cancel',
          placement: 'right',
          label: labels.syncCancel,
          variant: 'secondary',
          visible: true,
          disabled: syncing,
          onClick: () => setSyncConfirm(false),
          testId: `${TEST_ID}-toolbar-sync-cancel-btn`,
        },
      ];
    }

    return [
      ...left,
      {
        id: 'sync',
        placement: 'right',
        label: labels.syncAction,
        variant: 'secondary',
        visible: true,
        disabled: syncing,
        onClick: () => setSyncConfirm(true),
        testId: `${TEST_ID}-toolbar-sync-btn`,
      },
    ];
  }, [refresh, syncConfirm, syncing, handleSync, perms.canWrite]);

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-date`,
        content: (
          <LinListFilterDateRangeField
            label="Thời gian"
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            expandAriaLabel="Thêm ngày kết thúc"
            onChange={(from, to) => {
              setFromDate(from ?? '');
              setToDate(to ?? '');
              setCurrentPage(1);
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-dept`,
        content: (
          <Select
            label="Phòng ban"
            value={departmentId}
            onChange={e => {
              setDepartmentId(e.target.value);
              setCurrentPage(1);
            }}
            options={[
              { value: '', label: labels.deptAll },
              ...depts.map(d => ({ value: d.id, label: d.name })),
            ]}
          />
        ),
      },
    ],
    [fromDate, toDate, departmentId, depts],
  );

  const listBody =
    !showTableLoading && items.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colDate}</th>
              <th>{labels.colName}</th>
              <th>{labels.colCheckIn}</th>
              <th>{labels.colCheckOut}</th>
              <th className={erp.colRight}>{labels.colOvertime}</th>
              <th>{labels.colStatus}</th>
            </tr>
          </thead>
          <tbody>
            {items.map(r => (
              <tr
                key={r.id}
                data-testid={`${TEST_ID}-row-${r.id}`}
                className={r.isLate ? erp.rowDanger : undefined}
              >
                <td>{formatDateLocal(r.attendanceDate)}</td>
                <td>{r.employeeName}</td>
                <td>{formatTime(r.checkIn)}</td>
                <td>{formatTime(r.checkOut)}</td>
                <td className={erp.colRight}>
                  {r.overtimeHours > 0 ? r.overtimeHours.toFixed(1) : '—'}
                </td>
                <td>
                  <span className={r.isLate ? erp.tagWarning : erp.tagSuccess}>
                    {r.isLate ? labels.statusLate : labels.statusOnTime}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.catalogListRoot}
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="catalog"
        filterBarLayout="compact"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={erp.catalogListPage}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-clock',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        toolbarProps={{
          testIdPrefix: TEST_ID,
          profile: 'catalog',
          actions: toolbarActions,
        }}
        listTitle={labels.listTitle}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footerPagination={{
          page: currentPage,
          pageSize: PAGE_SIZE,
          totalCount,
          onPageChange: setCurrentPage,
          itemLabel: labels.itemLabel,
        }}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default ChamCongPage;
